export const WORLD_MAP_WIDTH = 1000;
export const WORLD_MAP_HEIGHT = 679;

const LAT_MAX = 84;
const LAT_MIN = -60;
const mercY = (lat: number) => Math.log(Math.tan(Math.PI / 4 + (lat * Math.PI) / 360));
const Y_TOP = mercY(LAT_MAX);
const Y_BOTTOM = mercY(LAT_MIN);

/** Project WGS84 lat/lon onto the map's SVG coordinate space. */
export function projectPoint(lat: number, lon: number): { x: number; y: number } {
  const clamped = Math.max(LAT_MIN, Math.min(LAT_MAX, lat));
  return {
    x: ((lon + 180) / 360) * WORLD_MAP_WIDTH,
    y: ((Y_TOP - mercY(clamped)) / (Y_TOP - Y_BOTTOM)) * WORLD_MAP_HEIGHT,
  };
}

